import java.util.*;

public class App {
    public static void main(String[] args) {
        Set<String> courseA = new HashSet<>(Arrays.asList("S01", "S02", "S03", "S04"));
        Set<String> courseB = new HashSet<>(Arrays.asList("S03", "S04", "S05", "S06"));

        // Union
        Set<String> union = new HashSet<>(courseA);
        union.addAll(courseB);
        List<String> sortedUnion = new ArrayList<>(union);
        Collections.sort(sortedUnion);
        System.out.println("Union (all enrolled): " + sortedUnion);

        // Intersection
        Set<String> intersection = new HashSet<>(courseA);
        intersection.retainAll(courseB);
        List<String> sortedIntersection = new ArrayList<>(intersection);
        Collections.sort(sortedIntersection);
        System.out.println("Intersection (both courses): " + sortedIntersection);

        // Difference A - B
        Set<String> onlyA = new HashSet<>(courseA);
        onlyA.removeAll(courseB);
        List<String> sortedDiff = new ArrayList<>(onlyA);
        Collections.sort(sortedDiff);
        System.out.println("Only in A: " + sortedDiff);
    }
}

