import java.util.*;

public class App {
    public static void main(String[] args) {
        String s = "aabbcddefa";

        // Count occurrences (Map — needed for counts)
        Map<Character, Integer> count = new HashMap<>();
        for (char c : s.toCharArray()) {
            count.put(c, count.getOrDefault(c, 0) + 1);
        }

        // First char with count == 1 (maintain original order — use string scan)
        char result = ' ';
        for (char c : s.toCharArray()) {
            if (count.get(c) == 1) {
                result = c;
                break;
            }
        }

        System.out.println("First unique: " + result);
    }
}

