import java.util.*;

class SessionTracker {
    private Set<String> activeUsers = new HashSet<>();
    private Set<String> blockedUsers = new HashSet<>();

    public boolean login(String userId) {
        if (blockedUsers.contains(userId)) return false;
        return activeUsers.add(userId);
    }

    public void logout(String userId) {
        activeUsers.remove(userId);
    }

    public void block(String userId) {
        blockedUsers.add(userId);
        activeUsers.remove(userId);
    }

    public boolean isActive(String userId) { return activeUsers.contains(userId); }
    public boolean isBlocked(String userId) { return blockedUsers.contains(userId); }
    public int activeCount() { return activeUsers.size(); }
}

public class App {
    public static void main(String[] args) {
        SessionTracker tracker = new SessionTracker();
        tracker.login("aisha");
        tracker.login("raj");
        tracker.login("priya");
        tracker.block("raj");       // block and remove from active
        tracker.login("raj");       // attempt to login — blocked, fails

        System.out.println("Aisha active: " + tracker.isActive("aisha"));
        System.out.println("Raj blocked: " + tracker.isBlocked("raj"));
        System.out.println("Raj active: " + tracker.isActive("raj"));
        System.out.println("Active users: " + tracker.activeCount());
    }
}

