import java.util.*;

class SocialGraph {
    private Map<String, Set<String>> friends = new HashMap<>();

    private Set<String> getFriends(String user) {
        return friends.computeIfAbsent(user, k -> new HashSet<>());
    }

    public void addFriendship(String a, String b) {
        getFriends(a).add(b);
        getFriends(b).add(a);
    }

    public Set<String> mutualFriends(String a, String b) {
        Set<String> mutual = new HashSet<>(getFriends(a));
        mutual.retainAll(getFriends(b));
        return mutual;
    }

    public Set<String> suggestions(String user) {
        Set<String> myFriends = getFriends(user);
        Set<String> suggested = new HashSet<>();

        // Friends of friends
        for (String friend : myFriends) {
            suggested.addAll(getFriends(friend));
        }

        // Remove self and existing friends
        suggested.remove(user);
        suggested.removeAll(myFriends);

        return suggested;
    }
}

public class App {
    public static void main(String[] args) {
        SocialGraph graph = new SocialGraph();
        graph.addFriendship("Aisha", "Raj");
        graph.addFriendship("Aisha", "Priya");
        graph.addFriendship("Raj", "Vikram");
        graph.addFriendship("Priya", "Vikram");

        Set<String> mutual = graph.mutualFriends("Aisha", "Raj");
        List<String> mutualSorted = new ArrayList<>(mutual);
        Collections.sort(mutualSorted);
        System.out.println("Aisha & Raj mutual: " + mutualSorted);

        Set<String> suggestions = graph.suggestions("Aisha");
        List<String> suggSorted = new ArrayList<>(suggestions);
        Collections.sort(suggSorted);
        System.out.println("Suggestions for Aisha: " + suggSorted);
    }
}

import java.util.*;

class Course {
    String code, title;
    Set<String> prerequisites;

    Course(String code, String title, String... prereqs) {
        this.code = code; this.title = title;
        this.prerequisites = new HashSet<>(Arrays.asList(prereqs));
    }
}

class Student {
    String name;
    Set<String> completed;

    Student(String name, String... completed) {
        this.name = name;
        this.completed = new HashSet<>(Arrays.asList(completed));
    }
}

class Validator {
    public boolean canEnroll(Student s, Course c) {
        return s.completed.containsAll(c.prerequisites);
    }

    public Set<String> missingPrerequisites(Student s, Course c) {
        Set<String> missing = new HashSet<>(c.prerequisites);
        missing.removeAll(s.completed);
        return missing;
    }

    public List<Course> eligibleCourses(Student s, List<Course> courses) {
        List<Course> eligible = new ArrayList<>();
        for (Course c : courses) {
            if (canEnroll(s, c)) eligible.add(c);
        }
        return eligible;
    }
}

public class App {
    public static void main(String[] args) {
        Course dsa = new Course("DSA", "Data Structures", "Java101", "Math101");
        Course webDev = new Course("WebDev", "Web Development", "Java101");
        Course ml = new Course("ML", "Machine Learning", "Python101", "Math101");

        Student aisha = new Student("Aisha", "Java101", "Math101", "OOP101");
        Student raj = new Student("Raj", "Math101", "OOP101");  // missing Java101

        Validator v = new Validator();

        System.out.println("Aisha can enroll in DSA: " + v.canEnroll(aisha, dsa));
        System.out.println("Raj can enroll in DSA: " + v.canEnroll(raj, dsa));

        Set<String> missing = v.missingPrerequisites(raj, dsa);
        System.out.println("Raj missing: " + new TreeSet<>(missing));

        List<Course> allCourses = Arrays.asList(dsa, webDev, ml);
        List<Course> eligible = v.eligibleCourses(aisha, allCourses);
        List<String> eligibleNames = new ArrayList<>();
        for (Course c : eligible) eligibleNames.add(c.code);
        Collections.sort(eligibleNames);
        System.out.println("Aisha eligible courses: " + eligibleNames);
    }
}
